#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


vec2 adjuv=vec2(q3,q4);
vec2 adjuv2=vec2(q5,q6);
vec2 huv=uTexSize.zw*0.5;
vec2 aspc=vec2(q2,q1);
vec2 tuv=vUv;
vec3 my_scale,my_mean;
vec3 st,op,sp;
float mscale,i,mavr,j;
vec3 my_smp,c1,c2,c3,c4;
my_scale=texture(sampler_pw_main,vec2(q20,0.004));
mscale=2.98/(my_scale.z+1);
//mscale=1/(my_scale.z+1);
my_mean=mscale*my_scale.y;

//mscale=1;

op=texture(main,vUv);
sp=texture(base01,(0.8*0.2*q3)*vUv*0.15-adjuv*0.3*(my_mean*0.05+0.95));
sp=mix(sp,texture(base02,(0.75*0.25*q7)*op.xy*0.04-0.02+vUv*0.5-adjuv2*0.18*(my_mean*0.2+0.8)),op);
//sp=abs(cross(op,sp));
j=(op.x*op.y+op.x*op.z+op.y*op.z)*0.33333*0.7+(sp.x*sp.y+sp.x*sp.z+sp.y*sp.z)*0.3333333*0.3;
//j=op.z*0.3+sp.z*0.7;
i=texture(sampler_pw_main,vec2(q20,j));
i.x*=mscale;
i.x-=my_mean*0.5*(i);

c1=GetPixel(adjuv*0.3+0.5+(vUv-adjuv*0.3-0.5)*((1-i)*0.08+0.94));
//j=(c1.x+c1.y+c1.z+c1.)*0.3333;
j=(c1.x*c1.y+c1.x*c1.z+c1.y*c1.z)*0.333333;
//j=c1.z;
c2=texture(sampler_pw_main,vec2(q20,j));
c2.x=c2.x*mscale-my_mean*0.5*(j);

//c3=GetPixel(0.5+(vUv-0.5)*(c2.z*0.05+0.95));

ret=i<c2.x?(op*0.95+sp*0.05):c1;

//ret=(op*0.96+sp*0.04);
//ret=c1;
//ret=max(op*0.4+sp*0.6,c1);

//ret=tex2d(base01,0.5+(vUv-0.5)*(i*0.1+0.9));

//ret=i<my_mean?ret*ret:ret;
//ret=mix(ret,op,1-i);

//ret=mix(ret,GetPixel(0.5+(vUv-0.5)*(i*0.05+0.95)),i);

//ret=i>0?my_mean/*tex2d(base01,vUv.xy)*/:0;
//ret=my_smp.z;

//ret*=0.5;


  fragColor = ret;
}

